#include <iostream>
#include <iomanip>

using namespace std;

int main() {
    int N;
    cin >> N;

    for (int i = 0; i < N; i++) {
        int start = (i + 1) * N;
        for (int j = 0; j < N; j++) {
            if (j > 0) cout << ' ';
            cout << setw(3) << (start - j);
        }
        cout << '\n';
    }

    return 0;
}
